import { useEffect, useMemo, useState } from "react";
import axios from "axios";
import DashboardShell from "./components/DashboardShell";
import KpiGrid from "./components/KpiGrid";
import CategoryPie from "./components/CategoryPie";
import TrendLineChart from "./components/TrendLineChart";
import InsightsPanel from "./components/InsightsPanel";
import ModeToggle from "./components/ModeToggle";
import AdvisorForm from "./components/AdvisorForm";
import AdvisorReport from "./components/AdvisorReport";
import ErrorMessage from "./components/ErrorMessage";

const api = axios.create({
  baseURL: "http://127.0.0.1:8000/api",
  timeout: 10000,
});

const defaultAdvisorValues = {
  income: "",
  food: "",
  shopping: "",
  transport: "",
  utilities: "",
  entertainment: "",
  healthcare: "",
  other: "",
};

function buildAdvisorReport(values) {
  const expenseCategories = [
    { key: "food", label: "Food" },
    { key: "shopping", label: "Shopping" },
    { key: "transport", label: "Transport" },
    { key: "utilities", label: "Utilities" },
    { key: "entertainment", label: "Entertainment" },
    { key: "healthcare", label: "Healthcare" },
    { key: "other", label: "Other expenses" },
  ];

  const income = Number(values.income) || 0;
  const expenses = expenseCategories.reduce(
    (acc, item) => acc + (Number(values[item.key]) || 0),
    0
  );
  const netSavings = Math.max(income - expenses, 0);
  const savingsRate = income > 0 ? (netSavings / income) * 100 : 0;
  const healthScore = Math.min(Math.max(savingsRate, 0), 100);

  const largestCategory = expenseCategories.reduce((current, item) => {
    const amount = Number(values[item.key]) || 0;
    if (!current || amount > current.amount) {
      return { label: item.label, amount };
    }
    return current;
  }, null);

  const ratio = income > 0 ? expenses / income : 0;
  const recommendations = [
    savingsRate < 20
      ? "Increase your savings target to at least 20% of income."
      : "Keep your savings rate steady and invest surplus funds.",
    largestCategory && largestCategory.amount > 0
      ? `Review ${largestCategory.label.toLowerCase()} spending for potential cuts.`
      : "Maintain your current budget mix if it stays stable.",
    ratio > 0.9
      ? "Your expenses are near income. Prioritize essential needs and avoid new debt."
      : "Continue monitoring irregular costs and seasonal spending spikes.",
  ];

  const leaks = expenseCategories
    .filter((item) => Number(values[item.key]) > 0)
    .filter((item) => {
      if (item.key === "transport") return Number(values[item.key]) > 800;
      if (item.key === "entertainment") return Number(values[item.key]) > 700;
      if (item.key === "shopping") return Number(values[item.key]) > 900;
      return false;
    })
    .map((item) => `${item.label} looks higher than average; look for savings.`);

  if (leaks.length === 0) {
    leaks.push("No major money leaks detected. Keep monitoring your budget.");
  }

  return {
    totalExpenses: expenses,
    netSavings,
    savingsRate,
    healthScore,
    largestCategory: largestCategory ? largestCategory.label : "N/A",
    recommendations,
    leaks,
  };
}

function App() {
  const [mode, setMode] = useState("demo");
  const [summary, setSummary] = useState(null);
  const [categories, setCategories] = useState(null);
  const [monthlyTrend, setMonthlyTrend] = useState(null);
  const [healthScore, setHealthScore] = useState(null);
  const [insights, setInsights] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [advisorValues, setAdvisorValues] = useState(defaultAdvisorValues);
  const [advisorReport, setAdvisorReport] = useState(null);

  useEffect(() => {
    if (mode !== "demo") {
      setLoading(false);
      return;
    }

    async function fetchData() {
      try {
        setLoading(true);
        const [summaryRes, categoriesRes, trendRes, healthRes, insightsRes] =
          await Promise.all([
            api.get("/summary"),
            api.get("/categories"),
            api.get("/monthly-trend"),
            api.get("/health-score"),
            api.get("/insights"),
          ]);

        setSummary(summaryRes.data);
        setCategories(categoriesRes.data.categories);
        setMonthlyTrend(trendRes.data.monthly_trend);
        setHealthScore(healthRes.data.health_score);
        setInsights(insightsRes.data.insights);
        setError(null);
      } catch (err) {
        setError(err.response?.data?.detail || "Unable to load analytics data.");
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [mode]);

  const advisorReportMemo = useMemo(
    () => (mode === "advisor" ? buildAdvisorReport(advisorValues) : null),
    [advisorValues, mode]
  );

  const handleModeChange = (nextMode) => {
    setMode(nextMode);
    setError(null);
    setAdvisorReport(null);
    if (nextMode === "advisor") {
      setLoading(false);
    }
  };

  const handleAdvisorChange = (event) => {
    const { name, value } = event.target;
    setAdvisorValues((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleAdvisorSubmit = (event) => {
    event.preventDefault();
    setAdvisorReport(advisorReportMemo);
  };

  return (
    <DashboardShell loading={loading} error={error}>
      <ModeToggle mode={mode} onChange={handleModeChange} />

      {mode === "demo" ? (
        <>
          {summary && <KpiGrid summary={summary} healthScore={healthScore} />}
          <div className="grid gap-6 xl:grid-cols-[1.4fr_1fr]">
            <CategoryPie categories={categories} />
            <TrendLineChart monthlyTrend={monthlyTrend} />
          </div>
          <InsightsPanel insights={insights} />
        </>
      ) : (
        <div className="space-y-6">
          <AdvisorForm
            values={advisorValues}
            onChange={handleAdvisorChange}
            onSubmit={handleAdvisorSubmit}
          />
          <AdvisorReport report={advisorReport} />
        </div>
      )}

      {error && <ErrorMessage message={error} />}
    </DashboardShell>
  );
}

export default App;
